{
  "title": "बबल सॉर्ट की स्थिरता",
  "group": "सॉर्टिंग एल्गोरिदम",
  "options": [
    {
      "text": "अस्थिर"
    },
    {
      "text": "स्थिर"
    },
    {
      "text": "इम्प्लीमेंटेशन पर निर्भर करता है"
    },
    {
      "text": "न तो स्थिर, न ही अस्थिर"
    },
    {
      "text": "कॉम्प्लेक्सिटी स्थिरता निर्धारित करती है"
    }
  ],
  "questionProse": [
    "क्या बबल सॉर्ट एल्गोरिदम स्थिर है?"
  ],
  "explanationProse": [
    "बबल सॉर्ट एक स्थिर सॉर्टिंग एल्गोरिदम है, क्योंकि यह सॉर्टिंग के दौरान समान मान वाले तत्वों के मूल सापेक्ष क्रम को बनाए रखता है।"
  ]
}
